    "text": "=\n\n[]\n\n#\n\n集\n体\n正\n性\n总\n账\n for step in range(steps): phi = evolve_step(phi) sigma = phi ** 2\n\n#\n\n集\n体\n\nΔσ\n（卷\n三\n映\n射\n\n+\n\n卷\n四\n全\n局\n积\n分）\n delta_sigma = lambda_ * torch.gradient(sigma, spacing=dx, dim=[0,1,2])[0].mean() + \\ g * (torch.gradient(sigma, spacing=dx, dim=[0,1,2])[0]**2).mean() + \\ kappa * (torch.gradient(sigma, spacing=dx, dim=[0,1,2])[0]**3).mean()\n\n#\n\n集\n体\n\nΣ\n⁺\n（涌\n现\n\n-\n\n耗\n散）\n\nE_emerge\n\n=\n\n(sigma.mean()\n\n-\n\nsigma.mean())\n\n#\n\n简\n化\n：\n实\n际\n用\n多\n智\n能\n体\n关\n系\n场\n计\n算\n Gamma_diss = gamma0 * sigma.mean() + gamma2 * sigma.std() Sigma_plus = E_emerge - Gamma_diss sigma_history.append(sigma.mean().item()) delta_sigma_history.append(delta_sigma.item()) Sigma_plus_history.append(Sigma_plus.item())\n#\n\n======================\n\n可\n视\n化\n（背\n景\n海\n\n+\n\n集\n体\n\nΣ\n⁺\n）\n\n======================\n plt.figure(figsize=(15, 8)) plt.subplot(3, 1, 1) plt.plot(sigma_history, label=' 集 体 背 景 海 密 度 σ')\nplt.title('3D\n\nGPU\n\n模\n拟\n：\n集\n体\n背\n景\n海\n演\n化\n')\n plt.legend() plt.subplot(3, 1, 2)\nplt.plot(delta_sigma_history,\n\nlabel='\n集\n体\n\nΔσ\n（制\n度\n情\n绪\n势\n差）\n',"
