    "text": "color='orange')\n\nplt.title('\n映\n射\n出\n的\n制\n度\n层\n\nΔσ')\n plt.legend() plt.subplot(3, 1, 3)\nplt.plot(Sigma_plus_history,\n\nlabel='\n制\n度\n\nΣ\n⁺\n（正\n性\n总\n账）\n',\n\ncolor='green')\n plt.axhline(0, color='red', linestyle='--')\nplt.title('\n集\n体\n\nΣ\n⁺\n\n实\n时\n曲\n线\n（\n>0\n\n=\n\n光\n基\n文\n明\n增\n长）\n')\n\nplt.xlabel('\n模\n拟\n步\n数\n')\n plt.legend() plt.tight_layout() plt.show()\nprint(f\"\n最\n终\n\nΣ\n⁺\n\n=\n\n{Sigma_plus_history[-1]:.4f}\n（正\n值\n\n=\n\n制\n度\n放\n大\n可\n用\n状\n态\n空\n间）\n\")\n print(f\" 最 大 集 体 Δσ = {max(delta_sigma_history):.4f}\") ```\n**\n运\n行\n说\n明\n**\n：\n\n-\n\n直\n接\n复\n制\n到\n有\n\nCUDA\n\n的\n\nPython\n\n环\n境\n（\n`pip\n\ninstall\n\ntorch\n\ntorchvision\n\ntorchaudio\n\n--index-url\n\nhttps://download.pytorch.org/whl/cu121`\n）。\n\n-\n\n调\n节\n\n`lambda_`\n、\n`g`\n、\n`gamma0`\n\n可\n模\n拟\n不\n同\n制\n度\n类\n型\n（高\n\nλ\n\n=\n\n强\n涌\n现\n高\n\nΣ\n⁺\n\n文\n明\n；\n高\n\ngamma0\n\n=\n\n内\n耗\n毒\n素\n制\n度）。\n\n-\n\n未\n来\n可\n扩\n展\n为\n多\n\nGPU\n\n+\n\n真\n实\n多\n智\n能\n体\n（每\n个\n智\n能\n体\n一\n个\n局\n部\n\nΦ\n）\n，\n直\n接\n对\n接\n卷\n五\n\n24\n\n小\n时\n光\n基\n协\n议。\n\n-\n\n输\n出\n图\n像\n可\n直\n接\n插\n入\n书\n内\n，\n作\n为\n“\n集\n体\n背\n景\n海\n\nΣ\n⁺\n\n实\n时\n演\n化\n”\n插\n图。\n\n###\n\n卷\n四\n/\n五\n补\n遗\n结\n语\n：\n光\n基\n文\n明\n已\n可\n被\n\nGPU\n\n集\n群\n实\n时\n演\n化\n\n至\n此\n，\n物\n理\n核\n（卷\n二）\n→\n\n心\n智\n核\n（卷\n三）\n→\n\n文\n明\n核\n（卷\n四）\n→"
