    "text": "codePython\nimport numpy as np from scipy.integrate import odeint import matplotlib.pyplot as plt def background_potential_deriv(phi, m=1.0, lambda_=10.0, g=1.0, kappa=0.1):\n#\n\n背\n景\n海\n势\n能\n非\n线\n性\n导\n数\n\n(\n卷\n二\n) return m**2 * phi - lambda_ * phi**3 + g * phi**5 + kappa * phi**7 def scalar_field_rhs(y, t, dx, m=1.0, lambda_=10.0, g=1.0, kappa=0.1, gamma0=0.05): # 1D Klein-Gordon + 耗 散 ( 卷 二 公 式 7.2 + 7.3) phi = y.reshape((N,)) d2phi_dx2 = np.gradient(np.gradient(phi, dx), dx) U_prime = background_potential_deriv(phi, m, lambda_, g, kappa) dissipation = gamma0 * phi\n#\n\nΓ_\nphys\n\n线\n性\n耗\n散 dphi_dt = d2phi_dx2 - U_prime - dissipation return dphi_dt.flatten()\n#\n\n参\n数\n设\n置\n\n(\n可\n调\n参\n验\n证\n不\n同\n性\n格\n/\n情\n绪\n强\n度\n) N = 256; L = 20.0; dx = L / (N - 1) x = np.linspace(0, L, N) t_span = np.linspace(0, 100, 1000)\n#\n\n初\n始\n小\n扰\n动\n\n(\n模\n拟\n遭\n遇\n外\n界\n刺\n激\n的\n宇\n宙\n背\n景\n涨\n落\n) np.random.seed(42) phi0 = 0.05 * np.sin(4 * np.pi * x / L) + 0.01 * np.random.randn(N) # 演 化 求 解 sol = odeint(scalar_field_rhs, phi0.flatten(), t_span) phi_t = sol.reshape((len(t_span), N))"
