    "text": "#\n\n跨\n层\n计\n算\n映\n射\n情\n绪\n\nΔσ sigma_t = phi_t ** 2 delta_sigma_t = np.gradient(sigma_t, axis=1) * 5.0 + 0.1 * np.gradient(np.gradient(sigma_t, axis=1),\naxis=1)\n#\n\n提\n取\n情\n绪\n四\n参\n数\n\nE(t) amplitude_A = np.max(np.abs(delta_sigma_t), axis=1) sign_s = np.sign(np.mean(delta_sigma_t, axis=1)) coupling_kappa = np.std(delta_sigma_t, axis=1)\n#\n\n空\n间\n扩\n散\n=\n感\n染\n力 print(\nf\"\n最\n大\n情\n绪\n势\n差\n\nΔσ:\n {np.max(amplitude_A):.3f}\") print(f\" 平 均 感 染 力 κ: {np.mean(coupling_kappa):.3f}\") print(\nf\"\n情\n绪\n正\n负\n翻\n转\n次\n数\n:\n {np.sum(np.diff(sign_s) != 0)}\")\n(\n注\n：\n复\n制\n至\n任\n意\n\nPython\n\n环\n境\n即\n可\n运\n行。\n调\n节\n\nλ/\ng\n\n即\n可\n模\n拟\n从\n暴\n怒\n到\n持\n久\n低\n频\n黑\n子\n的\n全\n谱\n系\n情\n绪！\n)\n\n光\n，\n已\n从\n宇\n宙\n底\n层\n，\n精\n确\n照\n进\n了\n每\n一\n个\n人\n的\n情\n绪\n与\n灵\n魂！\n\n第\n十\n七\n章\n\n爱\n与\n关\n系\n：\n从\n两\n个\n孤\n独\n的\n质\n点\n，\n到\n一\n个\n伟\n大\n的\n“\n涌\n现\n场\n”\n\n题\n记\n\n爱\n情\n，\n或\n者\n任\n何\n深\n度\n的\n关\n系\n，\n从\n来\n都\n不\n是\n“\n两\n个\n人\n相\n互\n感\n觉\n良\n好\n”\n那\n么\n肤\n浅\n和\n简\n单。\n\n当\n真\n实、\n高\n强\n度\n的\n连\n接\n一\n旦\n发\n生\n，\n就\n不\n再\n只\n是\n一\n个\n“\n我\n”\n加\n一\n个\n“\n你\n”\n的\n枯\n燥\n并\n列。\n\n在\n无\n限\n随\n机\n的\n宇\n宙\n海\n中\n，\n在\n两\n颗\n灵\n魂\n碰\n撞\n的\n电\n光\n火\n石\n之\n间\n，\n会\n长\n出\n第\n三\n样\n极\n其\n耀\n眼、\n也\n极\n其\n脆\n弱\n的\n东\n西。\n\n这\n，\n就\n是\n爱\n的\n物\n理\n学。\n\n一、\n\n关\n系\n不\n是\n两\n个\n人\n，\n而\n是\n“\n第\n三\n者\n”\n的\n恢\n弘\n诞\n生"
