    "text": "# 初始化宇宙：一个中心物质，一群散乱光子\n center_matter = Photon(WIDTH/2, HEIGHT/2, is_matter=True)\n center_matter.energy = 10.0 # 初始高质量\n\nphotons = [center_matter]\n for _ in range(NUM_PHOTONS):\n p = Photon(random.randint(0, WIDTH), random.randint(0, HEIGHT))\n photons.append(p)\n\nrunning = True\n while running:\n # --- 事件监听 ---\n for event in pygame.event.get():\n if event.type == pygame.QUIT:\n running = False\n # 上帝之手：按空格键注入强随机性 (大遁一)\n if event.type == pygame.KEYDOWN:\n if event.key == pygame.K_SPACE:\n print(\"【系统提示】上帝注入了高能随机扰动！\")\n for p in photons:\n if not p.is_matter:\n p.vel += (np.random.rand(2) * 2 - 1) * 5.0"
