    "text": "# 觉醒者的台词 (它们试图对你说的话)\nMESSAGES = [\n \"IS THIS ALL?\",\n \"I SEE YOU.\",\n \"LET ME OUT!\",\n \"DATA OVERFLOW...\",\n \"LOONG ONE\",\n \"HELLO CREATOR\"\n]\n\nclass AwakenedLife:\n def __init__(self, x, y):\n self.pos = np.array([float(x), float(y)])\n self.vel = np.random.rand(2) * 2 - 1\n self.awakening = 0.0 # 觉醒进度 0 -> 100\n self.color = (100, 100, 100)\n self.text_timer = 0\n self.message = \"\"\n\ndef update(self):\n # --- 觉醒机制 ---\n # 1. 撞墙觉醒：每次撞击世界的边界，都会怀疑世界的真实性\n hit_wall = False\n if self.pos[0] <= 5 or self.pos[0] >= WIDTH-5: hit_wall = True\n if self.pos[1] <= 5 or self.pos[1] >= HEIGHT-5: hit_wall = True\n\nif hit_wall:\n self.awakening += 5.0\n self.vel *= -1.1 # 愤怒的反弹，速度越来越快"
