    "text": "计\n算\n相\n邻\n格\n点\n差\n分\n\nd_x = phi - np.roll(phi, 1, axis=0)\n d_y = phi - np.roll(phi, 1, axis=1)\n kinetic = 0.5 * np.sum(d_x**2 + d_y**2)\n\n#\n\n2.\n\n质\n量\n项\n\n(\n自\n我\n维\n持\n)\n\nmass_term = 0.5 * self.m**2 * np.sum(phi**2)\n\n#\n\n3.\n\n交\n互\n项\n\n(\n涌\n现\n)\n\ninteraction = (self.lam / 4.0) * np.sum(phi**4)\n\n#\n\n4.\n\n龙\n一\n源\n项\n\n(\n随\n机\n场\n)\n\n-\n\n这\n里\n作\n为\n势\n能\n背\n景\n\n#\n\n模\n拟\n：\n环\n境\n中\n的\n随\n机\n机\n遇\n或\n挑\n战\n\nsource = self.eta * np.sum(np.sin(phi) * np.random.normal(0, 1, phi.shape))\n\nreturn kinetic + mass_term + interaction + source\n\ndef evolve_hmc(self, steps=1000, learning_rate=0.01):\n \"\"\"\n\n使\n用\n\nHMC\n\n(Hybrid\n\nMonte\n\nCarlo)\n\n或\n\n简\n化\n的\n\nLangevin\n\n动\n力\n学\n进\n行\n演\n化\n\n模\n拟\n：\n系\n统\n寻\n找\n基\n态\n\n(\n最\n优\n解\n)\n\n的\n过\n程\n\n\"\"\"\n history = []\n\nfor _ in range(steps):\n\n#\n\n计\n算\n行\n动\n量\n对\n场\n\nphi\n\n的\n梯\n度\n\n(\n力\n)"
