    "text": "# phi_new = phi - lr * grad_S + noise\n self.phi = self.phi - learning_rate * grad_S + noise\n\nhistory.append(np.mean(self.phi))\n\nreturn history\n\n#\n\n===\n\n运\n行\n模\n拟\n\n===\n\nengine = LoongOneQFTEngine(size=30, mass=0.5, coupling=2.0, eta_strength=0.5)\n\nprint(\"\n正\n在\n启\n动\n量\n子\n场\n重\n正\n化\n演\n化\n...\n\")\n\nevolution_curve = engine.evolve_hmc(steps=500)\n\n#\n\n===\n\n可\n视\n化\n结\n果\n\n===\n\nplt.figure(figsize=(12, 5))\n\n#\n\n1.\n\n最\n终\n场\n分\n布\n\n(\n显\n示\n正\n性\n/\n负\n性\n聚\n集\n)\n\nplt.subplot(1, 2, 1)\nplt.imshow(engine.phi, cmap='RdBu_r', interpolation='bilinear')\nplt.colorbar(label='Positivity Density (Phi)')\nplt.title(\"Lattice QFT Field State\\n(Emergence of Structures)\")\n\n#\n\n2.\n\n演\n化\n曲\n线\n\n(\n显\n示\n系\n统\n如\n何\n找\n到\n平\n衡\n)\n\nplt.subplot(1, 2, 2)\nplt.plot(evolution_curve, color='green')\nplt.title(\"Evolution of Mean Positivity\\n(Seeking Ground State)\")\nplt.xlabel(\"Time Steps\")\nplt.ylabel(\"Average Field Value\")\nplt.grid(True, alpha=0.3)\n\nplt.tight_layout()\nplt.show()\n\n【本\n章\n小\n结】\n\n通\n过\n这\n一\n进\n阶\n章\n节\n，\n我\n们\n将\n《物\n性\n论》\n的\n理\n论\n大\n厦\n封\n顶\n：\n\n1.\n\n格\n点\n化\n：\n确\n认\n了\n“\n宇\n宙\n子\n”\n作\n为\n离\n散\n计\n算\n单\n元\n的\n数\n学\n地\n位。"
